// Time:  O(n^2)
// Space: O(n)

class Solution {
public:
    bool splitString(string s) {
        return backtracking(s, 0, -1, 0);
    }

private:
    bool backtracking(const string& s, int i, int64_t num, int cnt) {
        if (i == size(s)) {
            return cnt >= 2;
        }
        int64_t new_num = 0;
        for (int j = i; j < size(s); ++j) {
            new_num = new_num * 10 + (s[j] - '0');
            if (new_num >= 1e10) {
                break;
            }
            if (new_num >= num && num >= 0) {
                break;
            }
            if ((num == -1 || (num - 1) == new_num) && backtracking(s, j + 1, new_num, cnt + 1)) {
                return true;
            }
        }
        return false;
    }
};

# Time:  O(n^2)
# Space: O(n)

class Solution(object):
    def splitString(self, s):
        """
        :type s: str
        :rtype: bool
        """
        def backtracking(s, i, num, cnt):
            if i == len(s):
                return cnt >= 2
            new_num = 0
            for j in xrange(i, len(s)):
                new_num = new_num*10 + int(s[j])
                if new_num >= num >= 0:
                    break
                if (num == -1 or num-1 == new_num) and backtracking(s, j+1, new_num, cnt+1):
                    return True
            return False

        return backtracking(s, 0, -1, 0)
